// 肩臂之錨（逐尊臂筆共此座標）：肩峰外緣・腋——杆自肩發
export const 肩錨 = { 峰x: 13.4, 峰z: 28.6, 腋x: 10.9, 腋z: 32.4 };
// 上臂常勢：肩峰而下至肘（垂臂之尊共此段；舉臂之尊自運勿呼）。
// d＝-1 尊右（畫面左，陽側線輕）、+1 尊左（陰側線重）；肘z 預設 39.6。
export function 上臂常勢(筆, d, 肘z = 39.6) {
    const { M, C, Qk, S, 陰, 陽 } = 筆;
    const 側 = d < 0 ? 陽 : 陰;
    側(() => {
        M(d * 13.4, 28.6);
        C(d * 14.4, 30.6, d * 14.9, 33.4, d * 14.6, 36.4);
        Qk(d * 14.45, Math.max(37.6, 肘z - 1.6), d * 13.9, 肘z);
        S();
        M(d * 10.9, 32.6);
        C(d * 11.3, 34.6, d * 11.5, 36.2, d * 11.35, Math.min(38.2, 肘z - 1.4));
        S();
    });
}
// 前臂：肘→腕之雙緣（寬根→寬梢漸斂，外緣微弓＝肌腹）；先蔽後勒——
// 底線（條帛・軀幹・先落之臂）沒於臂後，線描無遮擋之律。弓正值向左法向鼓。
export function 前臂(bi, 筆, 肘, 腕, 相 = {}) {
    const { M, Qk, S } = 筆;
    const [ex, ez] = 肘, [wx, wz] = 腕;
    const dx = wx - ex, dz = wz - ez, L = Math.hypot(dx, dz) || 1;
    const nx = -dz / L, nz = dx / L;
    const w0 = (相.寬根 ?? 2.15) / 2, w1 = (相.寬梢 ?? 1.5) / 2;
    const 弓 = 相.弓 ?? 0.3;
    if (相.蔽 !== false) {
        const { ctx, u, Y } = bi;
        ctx.save();
        ctx.globalCompositeOperation = 'destination-out';
        ctx.beginPath();
        ctx.moveTo((ex + nx * w0) * u, Y(ez + nz * w0));
        ctx.lineTo((wx + nx * w1) * u, Y(wz + nz * w1));
        ctx.lineTo((wx - nx * w1) * u, Y(wz - nz * w1));
        ctx.lineTo((ex - nx * w0) * u, Y(ez - nz * w0));
        ctx.closePath();
        ctx.fill();
        ctx.restore();
    }
    const wm = (w0 + w1) / 2;
    M(ex + nx * w0, ez + nz * w0);
    Qk((ex + wx) / 2 + nx * (wm + 弓), (ez + wz) / 2 + nz * (wm + 弓), wx + nx * w1, wz + nz * w1);
    S();
    M(ex - nx * w0, ez - nz * w0);
    Qk((ex + wx) / 2 - nx * (wm + 弓 * 0.35), (ez + wz) / 2 - nz * (wm + 弓 * 0.35), wx - nx * w1, wz - nz * w1);
    S();
    // 肘帽：肘端外緣一弧，接上臂之杆（摺臂之尊開之——肘有轉，臂乃成臂）
    if (相.肘帽) {
        const φ = Math.atan2(ez - wz, ex - wx);
        bi.A(ex + Math.cos(φ) * w0 * 0.2, ez + Math.sin(φ) * w0 * 0.2, w0 * 0.66, φ - Math.PI / 2 + 0.22, φ + Math.PI / 2 - 0.22);
    }
}
// 三峰寶冠（預設）：冠帶綴珠，三峰表三部——十六大菩薩等通用之制
// （逐尊冠制經軌多不載〔闕〕，從現図白描之簡；五佛冠等專相由尊筆自供）
export function 三峰寶冠(bi) {
    const { M, Qk, C, S, 衣, 細 } = 運筆(bi);
    const { dot, dim } = bi;
    衣(() => {
        M(-5.5, 8.9);
        Qk(0, 7.7, 5.5, 8.9);
        S();
        M(-5.35, 7.7);
        Qk(0, 6.5, 5.35, 7.7);
        S();
        細(() => { for (const [bx, bz] of [[-4.2, 8.2], [-2.1, 7.6], [0, 7.35], [2.1, 7.6], [4.2, 8.2]])
            dot(bx, bz, 0.2); });
        // 三峰：中峰高而側峰讓，峰各承一珠
        M(-1.3, 6.7);
        Qk(-0.6, 4.6, 0, 4.4);
        Qk(0.6, 4.6, 1.3, 6.7);
        S();
        M(-4.3, 7.6);
        Qk(-3.6, 5.9, -3.0, 5.75);
        Qk(-2.4, 5.9, -2.0, 7.0);
        S();
        M(4.3, 7.6);
        Qk(3.6, 5.9, 3.0, 5.75);
        Qk(2.4, 5.9, 2.0, 7.0);
        S();
        細(() => { dot(0, 4.85, 0.24); dot(-3.0, 6.2, 0.2); dot(3.0, 6.2, 0.2); });
        // 冠繒：兩側垂帶（一杆而下，末梢微翻）
        for (const d of [-1, 1]) {
            dim(0.7, () => 細(() => {
                M(d * 5.8, 8.6);
                C(d * 7.9, 9.3, d * 8.3, 10.9, d * 8.9, 12.4);
                Qk(d * 9.25, 13.3, d * 8.7, 13.9);
                S();
            }));
        }
    });
}
